      className={`inline-flex items-center gap-1 px-2 py-1 rounded-md text-[11.5px] transition-colors ${active ? "text-emerald-400 bg-white/[0.04]" : "text-textSecondary hover:text-white hover:bg-white/[0.04]"}`}
    >
